def connect_wifi(ssid=None, password=None):
    if network is None:
        return
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if ssid and password:
        if not wlan.isconnected():
            wlan.connect(ssid, password)
            for _ in range(50):
                if wlan.isconnected():
                    break
                try:
                    time.sleep_ms(200)
                except Exception:
                    time.sleep(0.2)


